A simple example using switch-case to direct game updates based on enum states:

```cpp
enum class EEnemyState {
    Idle,
    Patrolling,
    Chasing,
    Attacking
};

void UpdateEnemyAI(EEnemyState CurrentState) {
    switch (CurrentState) {
        case EEnemyState::Idle:
            PlayIdleAnimation();
            break;
        case EEnemyState::Patrolling:
            MoveAlongPatrolPath();
            break;
        case EEnemyState::Chasing:
            FindPathToTarget(Player->Location);
            break;
        case EEnemyState::Attacking:
            TriggerMeleeAttack();
            break;
        default:
            break;
    }
}
```
